import{_ as a,c as s,a2 as i,o as t}from"./chunks/framework.DPuwY6B9.js";const k=JSON.parse('{"title":"主题","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/theme.md","filePath":"zh/advanced/theme.md","lastUpdated":1732603302000}'),l={name:"advanced/theme.md"};function r(n,e,p,h,d,o){return t(),s("div",null,e[0]||(e[0]=[i(`<h1 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h1><p>兰空图床 2.x 是一个全新的前后端分离架构，后端使用 <a href="https://laravel.com" target="_blank" rel="noreferrer">Laravel</a>，前端使用 <a href="https://cn.vuejs.org" target="_blank" rel="noreferrer">Vue3</a>、<a href="https://pinia.vuejs.org/zh" target="_blank" rel="noreferrer">Pinia</a>、<a href="https://www.naiveui.com" target="_blank" rel="noreferrer">Native UI</a>。</p><p>相较于以前的版本，现在的版本使用了 Native UI 作为前端框架，使得样式一致、更统一。除了后台管理，我们可以自定义前端的样式，甚至可以直接替换整个前端。</p><p>若想要修改前端样式，您需要熟悉以下前端技术：</p><ul><li><a href="https://nodejs.org" target="_blank" rel="noreferrer">NodeJS</a></li><li><a href="https://www.typescriptlang.org" target="_blank" rel="noreferrer">TypeScript</a></li><li><a href="https://cn.vitejs.dev" target="_blank" rel="noreferrer">Vite</a></li><li><a href="https://cn.vuejs.org" target="_blank" rel="noreferrer">Vue3</a></li><li><a href="https://pinia.vuejs.org" target="_blank" rel="noreferrer">Pinia</a></li><li><a href="https://router.vuejs.org" target="_blank" rel="noreferrer">Vue Router</a></li><li><a href="https://tailwindcss.com" target="_blank" rel="noreferrer">Tailwind CSS</a></li></ul><h2 id="主题是如何运作的" tabindex="-1">主题是如何运作的？ <a class="header-anchor" href="#主题是如何运作的" aria-label="Permalink to &quot;主题是如何运作的？&quot;">​</a></h2><p>在我们的程序根目录，存在一个 <code>web</code> 文件夹，此文件夹是完整的前端工程文件，在执行构建后会触发打包脚本。</p><p>脚本的主要目的是（您也可以不使用脚本，全程手动按以下步骤操作）：</p><ol><li>将入口文件 <code>index.html</code> 移动至根目录 <code>resources/views/themes/default</code> 文件夹中，并重命名为 <code>index.blade.php</code>。</li><li>将打包后的所有静态文件，移动至根目录 <code>public/themes/default</code> 文件夹。（注意，前端工程请求静态资源的路径需要修改，例如 vite 中可以配置 <code>build.assetsDir</code> 来修改静态资源目录）</li><li>然后在根目录 <code>resources/views/themes/default</code> 创建主题配置文件 <code>config.json</code>，文件内容类似：<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;默认主题&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;author&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Wisp X&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://github.com/wisp-x&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><p>完成上述操作后，主题会以模板引擎渲染的方式实现混合部署，首次加载通过 laravel 的 <a href="https://laravel.com/docs/11.x/blade" target="_blank" rel="noreferrer">Blade 模板</a> 渲染页面，然后后续请求都由前端工程以 <a href="https://developer.mozilla.org/zh-CN/docs/Glossary/SPA" target="_blank" rel="noreferrer">SPA 单页应用</a> 的方式显示页面交互。</p><p>其中 <code>default</code> 文件夹表示的是默认主题的唯一标识，如果您想开发自己的主题，您也需要为您的主题设置一个唯一标识。</p><p>要切换主题，可以前往后台管理-&gt;系统设置-&gt;网站设置中切换。</p><h2 id="修改默认主题" tabindex="-1">修改默认主题 <a class="header-anchor" href="#修改默认主题" aria-label="Permalink to &quot;修改默认主题&quot;">​</a></h2><p>要修改主题，您需要在您的电脑上安装 <a href="https://nodejs.org" target="_blank" rel="noreferrer">Nodejs</a>。</p><p>使用终端进入根目录中的 <code>web</code> 文件夹，运行调试命令启动开发服务器：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-cfelD" id="tab-sBUThfo" checked><label data-title="Yarn" for="tab-sBUThfo">Yarn</label><input type="radio" name="group-cfelD" id="tab-xW8m7hz"><label data-title="Npm" for="tab-xW8m7hz">Npm</label></div><div class="blocks"><div class="language-shell vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div></div></div><p>然后就可以愉快的修改样式了。</p><p>您还可以修改环境变量文件 <code>web/.env</code> 中的 <code>VITE_APP_API_URL</code> 参数值来调整接口地址。</p><p>默认主题内置了打包脚本，在您执行 <code>build</code> 命令后脚本会自动处理需要移动、重命名的文件，不需要额外操作。</p><p>只需在您修改了前端工程文件后，执行构建命令：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-T5lzC" id="tab-b6-PZ_d" checked><label data-title="Yarn" for="tab-b6-PZ_d">Yarn</label><input type="radio" name="group-T5lzC" id="tab-xrm5ZeP"><label data-title="Npm" for="tab-xrm5ZeP">Npm</label></div><div class="blocks"><div class="language-shell vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div></div></div><p>构建后不要忘记将以下目录重新上传到您的服务器站点中：</p><ul><li><code>public/themes</code></li><li><code>resources/views/themes</code></li></ul><h2 id="自定义主题" tabindex="-1">自定义主题 <a class="header-anchor" href="#自定义主题" aria-label="Permalink to &quot;自定义主题&quot;">​</a></h2><p>同样的，无论您是使用 React 或 Vue，只需理解 <a href="#主题是如何运作的">主题是如何运作的</a>，按步骤将打包后的静态文件、文件夹复制到指定位置即可。</p>`,25)]))}const u=a(l,[["render",r]]);export{k as __pageData,u as default};
